Jump to a local label. Useful for cleanup paths in low-level C when used carefully.

Example workflow — cleanup goto for multiple resources:
```c
int Run(void)
{
    int status = -1;
    FILE *file = NULL;
    unsigned char *buffer = NULL;

    file = fopen("data.bin", "rb");
    if (!file) goto cleanup;

    buffer = malloc(1024U);
    if (!buffer) goto cleanup;

    status = 0;

cleanup:
    free(buffer);
    if (file) fclose(file);
    return status;
}
```

Example workflow — Function with error path:
```c
int MyFunction(void)
{
    int status = 0;
    void *resource = NULL;

    resource = malloc(128);
    if (!resource)
    {
        status = -1;
        goto Error;
    }

Error:
    free(resource);
    return status;
}
```

