    perror("operation");
}
```

Allocate uninitialized storage.

Example workflow — malloc / free:
```c
int *buffer = (int *)malloc(count * sizeof(int));
if (!buffer)
{
    return -1;
}

/* use buffer */

free(buffer);
buffer = NULL;
```

Example workflow — malloc array with overflow check:
```c
#include <stdint.h>
#include <stdlib.h>

if (count > SIZE_MAX / sizeof(*values))
{
    return -1;
}
values = malloc(count * sizeof(*values));
if (!values) return -1;
```

Resize an allocation. Use a temporary variable to avoid losing the original pointer on failure.

Example workflow — calloc / realloc:
```c
int *values = (int *)calloc(count, sizeof(int));
if (!values)
{
    return -1;
}

int *resized = (int *)realloc(values, newCount * sizeof(int));
if (!resized)
{
    free(values);
    return -1;
}
values = resized;
```

Example workflow — safe realloc temporary pointer:
```c
void *newBuffer = realloc(buffer, newSize);
if (!newBuffer)
{
    /* buffer is still valid */
    return -1;
}
buffer = newBuffer;
```

