Move the file position indicator.

Example workflow — fseek ftell whole file read:
```c
FILE *file = fopen(path, "rb");
if (!file) return NULL;

fseek(file, 0, SEEK_END);
long length = ftell(file);
rewind(file);
if (length < 0) { fclose(file); return NULL; }

char *text = malloc((size_t)length + 1U);
if (!text) { fclose(file); return NULL; }

size_t readCount = fread(text, 1U, (size_t)length, file);
text[readCount] = '\0';
fclose(file);
```

Rename or move a file.

Example workflow — temporary file then atomic rename:
```c
FILE *file = fopen("config.tmp", "wb");
if (!file) return -1;

fwrite(data, 1U, size, file);
if (fflush(file) != 0) { fclose(file); return -1; }
fclose(file);

if (rename("config.tmp", "config.json") != 0) return -1;
```

