Decode a little-endian 16-bit value without alignment or aliasing assumptions.

Workflow example preserved from the former snippet:

static void WriteU16Be(unsigned char *dst, uint16_t value)
{
    dst[0] = (unsigned char)(value >> 8);
    dst[1] = (unsigned char)(value & 0xFFU);
}

static uint16_t ReadU16Be(const unsigned char *src)
{
    return (uint16_t)(((uint16_t)src[0] << 8) | src[1]);
}

