static void {{name}}(uint8_t *data, uint32_t value)
{
    data[0] = (uint8_t)((value >> 24) & UINT32_C(0xFF));
    data[1] = (uint8_t)((value >> 16) & UINT32_C(0xFF));
    data[2] = (uint8_t)((value >> 8) & UINT32_C(0xFF));
