typedef struct Arena
{
    unsigned char *data;
    size_t capacity;
    size_t used;
} Arena;

void *Arena_Alloc(Arena *arena, size_t size)
{
    if (!arena || size > arena->capacity - arena->used) return NULL;
    void *result = arena->data + arena->used;
    arena->used += size;
    return result;
}

void Arena_Reset(Arena *arena)
{
    arena->used = 0U;
}

