typedef struct IntVector
{
    int *data;
    size_t size;
    size_t capacity;
} IntVector;

int IntVector_Push(IntVector *vector, int value)
{
    if (vector->size == vector->capacity)
    {
        size_t next = vector->capacity ? vector->capacity * 2U : 8U;
        int *data = realloc(vector->data, next * sizeof(*data));
        if (!data) return -1;
        vector->data = data;
        vector->capacity = next;
    }
    vector->data[vector->size++] = value;
    return 0;
}

