    size_t head;
    size_t tail;
    size_t count;
} ByteRing;

int ByteRing_Push(ByteRing *ring, unsigned char value)
{
    if (ring->count == RING_CAPACITY) return -1;
    ring->data[ring->head] = value;
    ring->head = (ring->head + 1U) % RING_CAPACITY;
    ++ring->count;
    return 0;
}

