#include <stdint.h>

#if defined(__arm__) || defined(__aarch64__)
#define IO_BARRIER() __asm__ volatile ("dmb ish" ::: "memory")
#else
#define IO_BARRIER() do { } while (0)
#endif

typedef struct GpioRegisters
{
    volatile uint32_t MODE;
    volatile uint32_t OUTPUT;
} GpioRegisters;

#define GPIO0 ((GpioRegisters *)0x40020000u)

static void Gpio_SetMode(unsigned pin, unsigned mode)
{
    uint32_t shift = pin * 2u;
    uint32_t value = GPIO0->MODE;
    value &= ~(0x3u << shift);
    value |= ((mode & 0x3u) << shift);
    IO_BARRIER();
    GPIO0->MODE = value;
    IO_BARRIER();
}

