{
    STATE_IDLE,
    STATE_WAIT_REPLY,
    STATE_ERROR
} State;

void HandleEvent(Context *context, Event event)
{
    switch (context->state)
    {
        case STATE_IDLE:
            if (event == EVENT_START) context->state = STATE_WAIT_REPLY;
            break;
        case STATE_WAIT_REPLY:
            if (event == EVENT_TIMEOUT) context->state = STATE_ERROR;
            break;
        default:
            break;
    }
}

