Workflow examples retained from the previous pack:

```cpp
std::array<std::uint8_t, 256> rxBuffer{};

serial.async_read_some(boost::asio::buffer(rxBuffer),
    [&](const boost::system::error_code &error, std::size_t bytesRead)
    {
        if (!error)
        {
            ConsumeBytes(rxBuffer.data(), bytesRead);
            StartNextRead();
        }
    });

io.run();
```

Windows COM-port setup normally combines CreateFileA, GetCommState, SetCommState and SetCommTimeouts.

Workflow examples retained from the previous pack:

```cpp
#ifdef _WIN32
#include <windows.h>
#include <stdexcept>

HANDLE serial = CreateFileW(
    L"\\\\.\\COM12",
    GENERIC_READ | GENERIC_WRITE,
    0,
    nullptr,
    OPEN_EXISTING,
    FILE_ATTRIBUTE_NORMAL,
    nullptr);

if (serial == INVALID_HANDLE_VALUE)
{
    throw std::runtime_error("Unable to open COM port");
}

DCB dcb{};
dcb.DCBlength = sizeof(dcb);
GetCommState(serial, &dcb);
dcb.BaudRate = CBR_115200;
dcb.ByteSize = 8;
dcb.Parity = NOPARITY;
dcb.StopBits = ONESTOPBIT;
SetCommState(serial, &dcb);
#endif
```

```cpp
#ifdef _WIN32
