timeouts.ReadIntervalTimeout = 20;
timeouts.ReadTotalTimeoutConstant = 100;
timeouts.ReadTotalTimeoutMultiplier = 0;
timeouts.WriteTotalTimeoutConstant = 100;
SetCommTimeouts(serial, &timeouts);

DWORD written = 0;
