The libcurl easy interface configures one handle, performs a transfer and then cleans it up. Reuse handles for repeated transfers when appropriate.

Workflow examples retained from the previous pack:

```cpp
#include <curl/curl.h>
#include <string>

static std::size_t AppendResponse(char *data, std::size_t size, std::size_t count, void *userData)
{
    auto &response = *static_cast<std::string *>(userData);
    response.append(data, size * count);
    return size * count;
}

std::string response;
CURL *curl = curl_easy_init();
curl_easy_setopt(curl, CURLOPT_URL, "http://127.0.0.1:8080/api/status");
curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, AppendResponse);
curl_easy_setopt(curl, CURLOPT_WRITEDATA, &response);
const CURLcode result = curl_easy_perform(curl);
curl_easy_cleanup(curl);
```

```cpp
CURL *curl = curl_easy_init();
curl_slist *headers = nullptr;
headers = curl_slist_append(headers, "Content-Type: application/json");

const std::string payload = R"({"command":"start","channel":2})";
curl_easy_setopt(curl, CURLOPT_URL, "http://127.0.0.1:8080/api/command");
curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);
curl_easy_setopt(curl, CURLOPT_POSTFIELDS, payload.c_str());
curl_easy_setopt(curl, CURLOPT_POSTFIELDSIZE, static_cast<long>(payload.size()));

const CURLcode result = curl_easy_perform(curl);

curl_slist_free_all(headers);
curl_easy_cleanup(curl);
```

```cpp
/*
 libcurl easy interface:
   curl_easy_init
   curl_easy_setopt
   curl_easy_perform      // blocking transfer
   curl_easy_cleanup

 libcurl multi interface:
   curl_multi_init
   curl_multi_add_handle
   curl_multi_perform
   curl_multi_poll
   curl_multi_remove_handle
   curl_multi_cleanup
*/
```

