Use popen or _popen for simple command streaming.

Workflow examples retained from the previous pack:

```cpp
#include <array>
#include <cstdio>
#include <memory>

#ifdef _WIN32
#define popen _popen
#define pclose _pclose
#endif

std::array<char, 256> buffer{};
std::string output;
std::unique_ptr<FILE, int(*)(FILE*)> pipe(popen("my_command", "r"), pclose);
if (!pipe)
{
    throw std::runtime_error("Unable to open command pipe");
}

while (fgets(buffer.data(), static_cast<int>(buffer.size()), pipe.get()) != nullptr)
{
    output += buffer.data();
}
```

Open an existing Windows named pipe from a client.

