if (pipeHandle == INVALID_HANDLE_VALUE)
{
    return;
}

const char *message = "hello";
DWORD written = 0;
WriteFile(pipeHandle, message, static_cast<DWORD>(strlen(message)), &written, NULL);
CloseHandle(pipeHandle);
#endif
```

Create a parent-child byte pipe on POSIX systems.

Workflow examples retained from the previous pack:

```cpp
#ifndef _WIN32
#include <unistd.h>

int fds[2];
if (pipe(fds) == 0)
{
    const char message[] = "hello";
    write(fds[1], message, sizeof(message) - 1);

    char buffer[32] = {0};
    read(fds[0], buffer, sizeof(buffer));

    close(fds[0]);
    close(fds[1]);
}
#endif
```

