Thread of execution handle. The thread must be joined or detached before destruction.

Examples previously provided as snippets:

```cpp
#include <thread>

std::thread worker([]()
{
    std::cout << "Worker thread running" << std::endl;
});

worker.join();
```

```cpp
#include <functional>
#include <thread>

void Increment(int& value)
{
    ++value;
}

int counter = 0;
std::thread worker(Increment, std::ref(counter));
worker.join();
```

```cpp
#include <thread>
#include <utility>

class JoiningThread
{
public:
    template <typename Callable, typename... Args>
    explicit JoiningThread(Callable&& callable, Args&&... args)
        : thread_(std::forward<Callable>(callable), std::forward<Args>(args)...)
    {
    }

    JoiningThread(const JoiningThread&) = delete;
    JoiningThread& operator=(const JoiningThread&) = delete;

    ~JoiningThread()
    {
        if (thread_.joinable())
        {
            thread_.join();
        }
    }

private:
    std::thread thread_;
};
```

```cpp
#include <thread>
#include <utility>

std::thread worker([]()
{
    RunOperation();
});

std::thread owner = std::move(worker);

if (owner.joinable())
{
    owner.join();
}
```

```cpp
#include <thread>

/* Avoid detach() unless the lifetime of every captured resource is proven safe.
   A detached thread can outlive the object, function scope, or application state
   that created it. Prefer std::jthread or an owned std::thread joined explicitly. */

std::thread([]()
{
    RunSelfContainedBackgroundOperation();
}).detach();
```

