functions.longDescription:
Condition variable for coordinating threads waiting on shared state.

Examples previously provided as snippets:

```cpp
#include <condition_variable>
#include <mutex>
#include <queue>

std::mutex mutex;
std::condition_variable cv;
std::queue<int> queue;
bool done = false;

void Consumer()
{
    std::unique_lock<std::mutex> lock(mutex);
    cv.wait(lock, []() { return !queue.empty() || done; });

    while (!queue.empty())
    {
        int value = queue.front();
        queue.pop();
        (void)value;
    }
}
```

Wait until a predicate becomes true.

Examples previously provided as snippets:

```cpp
#include <condition_variable>
#include <mutex>

std::mutex mutex;
std::condition_variable cv;
bool ready = false;

std::unique_lock<std::mutex> lock(mutex);
cv.wait(lock, []()
{
    return ready;
});
```

Wait for a predicate with timeout.

Examples previously provided as snippets:

```cpp
#include <chrono>
#include <condition_variable>
#include <mutex>

using namespace std::chrono_literals;

std::unique_lock<std::mutex> lock(mutex);
const bool ready = cv.wait_for(lock, 500ms, []()
{
    return dataReady;
});

if (!ready)
