}
```

Wake one waiting thread.

Examples previously provided as snippets:

```cpp
#include <condition_variable>
#include <mutex>
#include <queue>

std::mutex mutex;
std::condition_variable cv;
std::queue<int> queue;

void Produce(int value)
{
    {
        std::lock_guard<std::mutex> lock(mutex);
        queue.push(value);
    }
    cv.notify_one();
}
