```cpp
#include <future>
#include <thread>

std::promise<int> promise;
std::future<int> result = promise.get_future();

std::thread producer([](std::promise<int> output)
{
    output.set_value(42);
}, std::move(promise));

const int value = result.get();
producer.join();
```

```cpp
