Publish an exception through a promise.

Examples previously provided as snippets:

```cpp
#include <exception>
#include <future>
#include <thread>

std::promise<int> promise;
std::future<int> result = promise.get_future();

std::thread producer([](std::promise<int> output)
{
    try
    {
        output.set_value(ComputeValue());
    }
    catch (...)
    {
        output.set_exception(std::current_exception());
    }
