```cpp
#include <chrono>

using namespace std::chrono_literals;

const auto deadline = std::chrono::steady_clock::now() + 2s;

while (!IsReady())
{
    if (std::chrono::steady_clock::now() >= deadline)
    {
        throw std::runtime_error("Timeout while waiting for device");
    }

    PollDevice();
}
```

```cpp
