```

Type-safe discriminated union.

Examples previously provided as snippets:

```cpp
#include <iostream>
#include <string>
#include <variant>

template <class... Callables>
struct Overload : Callables...
{
    using Callables::operator()...;
};

template <class... Callables>
Overload(Callables...) -> Overload<Callables...>;

std::variant<int, std::string> value = "ready";

std::visit(Overload{
    [](int number) { std::cout << number << '\n'; },
    [](const std::string& text) { std::cout << text << '\n'; }
}, value);
```

